import cache from 'cache'
import nucUtils from 'c_nucleus_utils'
import request from 'request'
import faults from 'c_fault_lib'
import _ from 'underscore'

if (script.arguments.new.c_status === script.arguments.old.c_status) return

nucUtils.AclManagment.canSetPublicUserStatus() // does the user have permission to set this status

const study = org.objects.c_study
  .find({ _id: script.arguments.old.c_study._id })
  .skipAcl()
  .grant(consts.accessLevels.read)
  .next()

const isEnrollmentStatus = study.c_subject_enrollment_status === script.arguments.new.c_status
const isSubjectIdEmpty = _.isEmpty(script.arguments.old.c_number)

if ((!study.hasOwnProperty('c_automatic_participant_id_generation') || study.c_automatic_participant_id_generation) && isSubjectIdEmpty && isEnrollmentStatus) {
  const { c_site } = script.arguments.old
  let site, nextNumber, autoGenerated = false

  if (c_site) {
    site = org.objects.c_site.find({ _id: c_site._id })
      .skipAcl()
      .grant(consts.accessLevels.read)
      .paths('c_number', 'c_country')
      .next()
  }
  for (let i = 0; i < 1000; i++) {
    nextNumber = nucUtils.getNextSubjectID(study, site)
    const user = org.objects.c_public_users.find({ c_number: nextNumber })
      .skipAcl()
      .grant(consts.accessLevels.read)
      .paths('c_number')
    if (!user.hasNext()) {
      autoGenerated = true
      break
    }
  }

  if (!autoGenerated) {
    faults.throw('axon.validationError.autoParticipantIDConflictsWithManualID')
  }
  const cacheKey = `autoUpdatePU_${script.arguments.old._id}`
  cache.set(cacheKey, {}, 15)
  org.objects.c_public_users
    .updateOne({
      _id: script.arguments.new._id
    },
    {
      $set: {
        c_number: nextNumber,
        c_enrollment_date: new Date()
          .toISOString()
      }
    })
    .skipAcl()
    .grant('update')
    .execute()
}